/**
 * Get the municipality name for a given dbuId.
 * Returns null if not found.
 */
export function getMunicipality(dbuId) {
  for (const [name, ids] of Object.entries(municipalities)) {
    if (ids.includes(dbuId)) return name;
  }
  return null;
}

/**
 * Get all dbuIds in a given municipality.
 */
export function getClubsByMunicipality(name) {
  return municipalities[name] ?? [];
}

/**
 * List all municipality names, sorted alphabetically.
 */
