  return ["Albertslund","Allerød","Assens","Ballerup","Billund","Bornholm","Brøndby","Brønderslev","Dragør","Egedal","Esbjerg","Fanø","Favrskov","Faxe","Fredensborg","Fredericia","Frederiksberg","Frederikshavn","Frederikssund","Furesø","Faaborg-Midtfyn","Gentofte","Gladsaxe","Greve","Gribskov","Guldborgsund","Haderslev","Halsnæs","Hedensted","Helsingør","Herning","Hillerød","Hjørring","Holbæk","Holstebro","Horsens","Høje-Taastrup","Hørsholm","Ikast-Brande","Ishøj","Jammerbugt","Kalundborg","Kerteminde","Kolding","København","Køge","Langeland","Lejre","Lemvig","Lolland","Lyngby-Taarbæk","Læsø","Middelfart","Morsø","Norddjurs","Nordfyns","Nyborg","Næstved","Odder","Odense","Odsherred","Randers","Rebild","Ringkøbing-Skjern","Ringsted","Roskilde","Samsø","Silkeborg","Skanderborg","Skive","Slagelse","Solrød","Stevns","Struer","Svendborg","Syddjurs","Sønderborg","Thisted","Tønder","Vallensbæk","Varde","Vejen","Vejle","Vesthimmerlands","Viborg","Vordingborg","Ærø","Aabenraa","Aalborg","Aarhus"];
